@code {
    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    private IComponentRenderMode? PageRenderMode => HttpContext is not null && IsStaticPage(HttpContext)
        ? null
        : new InteractiveServerRenderMode();

    private bool IsStaticPage(HttpContext context)
    {
        var endpoint = context.GetEndpoint();
        if (endpoint is null) return false;

        // Pages decorated with [RenderModeAttribute()] opt out of interactive rendering
        return endpoint.Metadata.GetMetadata<BlazorApp.Components.Pages.RenderModeAttribute>() is not null;
    }
}
"}

